def _build_employee_payload(test_data, config):
    """
    Constructs the request payload for /employees.

    Uses test_data (endpoint override) first, then config['test_data'] as fallback for optional fields.
    Returns dict.
    """
    payload = {}

    # Required fields from schema: jobTitle, name, email
    for field in ("jobTitle", "name", "email"):
        v = test_data.get(field)
        if v is not None:
            payload[field] = v
        elif "test_data" in config and config["test_data"].get(field):
            payload[field] = config["test_data"][field]

    # Optional field: id
    if "id" in test_data:
        payload["id"] = test_data["id"]
    elif "test_data" in config and config["test_data"].get("id"):
        payload["id"] = config["test_data"]["id"]

    return payload


@pytest.mark.smoke
def test_add_employee_success(api_client, config, merged_test_data):
    """
    Smoke test: Successful creation of employee(s) with only required fields.
    Required fields: jobTitle, name, email (id is optional).
    Payload and scenarios are loaded from employees.json via merged_test_data.
    """
    test_entries = merged_test_data(_endpoint_data_path)
    assert isinstance(test_entries, list), "Expected test data to be a list of test cases"

    for entry in test_entries:
        # Only exercise happy paths (statusCode == 201)
        if entry.get("statusCode") != 201:
            continue
        payload = _build_employee_payload(entry, config)

        # Validate request schema before sending
        request_valid = validator.validate_json(payload, schema_name="Employee")
        assert request_valid["valid"], f"Request payload validation failed: {request_valid.get('message')}"

        resp = api_client.post(_ENDPOINT, headers={"Content-Type": "application/json"}, json=payload)
        assert resp.status_code == 201, f"Expected status code 201, got {resp.status_code} ({resp.text})"

        # Validate response schema (even if empty, validator handles no-schema)
        response_valid = validator.validate_schema_by_response(_ENDPOINT, _METHOD, "201", resp)
        assert response_valid["valid"], f"Response schema invalid: {response_valid.get('message')}"


@pytest.mark.parametrize("error_case", [
    {
        "desc": "Missing required field 'jobTitle'",
        "omit": ["jobTitle"],
        "expected_status": 400,
    },
    {
        "desc": "Missing required field 'name'",
        "omit": ["name"],
        "expected_status": 400,
    },
    {
        "desc": "Missing required field 'email'",
        "omit": ["email"],
        "expected_status": 400,
    },
    {
        "desc": "Duplicate employee creation (conflict)",
        "use_existing": True,
        "expected_status": 409,
    }
])
def test_add_employee_negative_cases(api_client, config, merged_test_data, error_case):
    """
    Negative and boundary tests for the /employees endpoint:
        - Missing required fields returns 400
        - Conflict/deduplication returns 409
    """
    test_entries = merged_test_data(_endpoint_data_path)
    assert isinstance(test_entries, list) and test_entries, "Test data must have entries"

    base_entry = test_entries[0].copy()

    # Handle missing required field
    if error_case.get("omit"):
        for field in error_case["omit"]:
            base_entry.pop(field, None)
        payload = _build_employee_payload(base_entry, config)
    elif error_case.get("use_existing"):
        # Simulate conflict: re-use a valid employee (must have been created in a prior test)
        last_entry = test_entries[-1]
        payload = _build_employee_payload(last_entry, config)
    else:
        pytest.skip("No valid error_case specified")

    # Validate request schema: expect to fail validation only for missing required field
    request_valid = validator.validate_json(payload, schema_name="Employee")
    # Assignment: for required fields, jsonschema validation may fail, but API must also enforce it.
    # So we POST and expect a 400
    resp = api_client.post(_ENDPOINT, headers={"Content-Type": "application/json"}, json=payload)
    assert resp.status_code == error_case["expected_status"], (
        f"{error_case['desc']}: Expected {error_case['expected_status']}, got {resp.status_code} ({resp.text})"
    )
    # Response schema validation for error responses
    response_valid = validator.validate_schema_by_response(_ENDPOINT, _METHOD, str(error_case["expected_status"]), resp)
    assert response_valid["valid"], (
        f"{error_case['desc']}: Error response schema invalid: {response_valid.get('message')}"
    )

